// SwiftUI
@main
struct MyApp: App {
    @Environment(\.scenePhase) var scenePhase

    var body: some Scene {
        WindowGroup { ContentView() }
            .onChange(of: scenePhase) { _, phase in
                switch phase {
                case .active: break      // 前台活跃
                case .inactive: break    // 临时不活跃
                case .background: break  // 后台
                @unknown default: break
                }
            }
    }
}

