@Composable
fun ExpensiveCalculation(input: List<Int>) {
    // ❌ 每次重组都计算
    val result = input.sorted().take(10)

    // ✅ 只有 input 变化时重新计算
    val result = remember(input) { input.sorted().take(10) }
