class CounterService {
  final _controller = StreamController<int>.broadcast();
  int _count = 0;

  Stream<int> get countStream => _controller.stream;

  void increment() {
    _count++;
    _controller.sink.add(_count);  // 发送数据
  }

  void dispose() {
