// Dart — 没有 struct，用 class + copyWith 模拟值语义
class Point {
  final int x, y;
  const Point(this.x, this.y);
  Point copyWith({int? x, int? y}) => Point(x ?? this.x, y ?? this.y);
}

// Swift — struct 是值类型，赋值即拷贝
